import sys
import math

def main():
    N, M, K = map(int, sys.stdin.read().split())
    lcm = N * M // math.gcd(N, M)
    # Numbers divisible by N or M but not both
    # Count of such numbers up to x is: (x // N + x // M - 2 * x // lcm)
    low = 1
    high = 2 * 10**18  # A safe upper bound

    def count(x):
        return x // N + x // M - 2 * (x // lcm)

    while low < high:
        mid = (low + high) // 2
        if count(mid) < K:
            low = mid + 1
        else:
            high = mid
    print(low)

if __name__ == "__main__":
    main()
